namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

public partial class DocumentSummarizer : IDocumentSummarizer
{
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SentenceRegex().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count == 0)
            return text.Trim();

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        // Score sentences by word frequency relevance
        var wordFrequency = BuildWordFrequency(sentences);
        var scored = sentences
            .Select((sentence, index) => new
            {
                Sentence = sentence,
                Index = index,
                Score = ScoreSentence(sentence, wordFrequency)
            })
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static Dictionary<string, int> BuildWordFrequency(List<string> sentences)
    {
        var frequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in WordRegex().Matches(sentence).Select(m => m.Value))
            {
                if (word.Length <= 2) continue; // skip short words
                frequency[word] = frequency.GetValueOrDefault(word) + 1;
            }
        }
        return frequency;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequency)
    {
        var words = WordRegex().Matches(sentence).Select(m => m.Value).ToList();
        if (words.Count == 0) return 0;

        double score = words
            .Where(w => w.Length > 2)
            .Sum(w => wordFrequency.GetValueOrDefault(w));

        return score / words.Count;
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText is required." });

        if (request.MaxSentences < 1)
            return BadRequest(new { error = "MaxSentences must be at least 1." });

        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

